import * as XLSX from 'xlsx';
import dayjs from 'dayjs';

export const processCombinedData = (csvData, excelRaw, proyectadoManual = 239000) => {
  // 1. PROCESAR EXCEL
  const workbook = XLSX.read(excelRaw, { type: 'array' });
  const sheet = workbook.Sheets[workbook.SheetNames[0]];
  const rawMatrix = XLSX.utils.sheet_to_json(sheet, { header: 1 });

  // Limpiamos los headers de cualquier espacio invisible
  const headers = rawMatrix[3]?.map(h => String(h).trim()) || [];
  const dataRows = rawMatrix.slice(4);

  const easyDockingClean = dataRows.map(row => {
    let obj = {};
    headers.forEach((h, i) => obj[h] = row[i]);
    return obj;
  }).filter(item => 
    String(item['TIPO DE OPERACION'] || "").toUpperCase().includes("DESCARGA") && 
    String(item['Accion'] || "").toLowerCase() === "add"
  );

  // SUMA DE ARRIBADOS (Excel)
  const arribadoExcel = easyDockingClean.reduce((acc, curr) => {
    const valor = curr['CANT PAQUETES'] || 0;
    return acc + (parseFloat(valor) || 0);
  }, 0);

  // 2. PROCESAR CSV (Bipeados)
  const bipeadoCSV = csvData.filter(d => 
    d['Labeling Date Printed'] && String(d['Labeling Date Printed']).trim() !== ""
  ).length;

  // 3. CÁLCULOS EXACTOS PARA LAS CARDS
  const kpis = {
    proyectado: proyectadoManual.toLocaleString(),
    arribado: arribadoExcel.toLocaleString(),
    bipeado: bipeadoCSV.toLocaleString(),

    // Deltas
    arribadoBipeado: (arribadoExcel - bipeadoCSV).toLocaleString(),
    proyectadoBipeado: (proyectadoManual - bipeadoCSV).toLocaleString(),
    descargaHora: Math.round(arribadoExcel / 12).toLocaleString(), // 12hs de operación

    // Porcentajes para las burbujas
    pArribado: Math.round((arribadoExcel / proyectadoManual) * 100) || 0,
    pBipeo: Math.round((bipeadoCSV / proyectadoManual) * 100) || 0,

    // Velocidad (El 90 de tu imagen)
    velocidadReal: Math.round(bipeadoCSV / 8) || 0 // 8hs transcurridas
  };

  return {
    kpis,
    chartData: [], // Se llena con la lógica horaria
    tableData: [],
    matrix: { chasis: 0, camioneta: 0, semi: 0 }
  };
};
